clc; clear; close all;

%% ==============================
%  MODULE 1: SENSOR SIMULATION
%  Gas + IMU + Temp + Humidity
% ===============================

% Time settings
Fs = 1;                 % 1 Hz sampling
T  = 120;               % total time (seconds)
t  = 0:1:T;
N  = length(t);

%% ==============================
%  SENSOR SIGNAL GENERATION
% ===============================

% ---- Gas (ppm) ----
gas = 25 + 2*randn(1,N);                % normal background
gas(t > 40 & t <= 60) = linspace(30,120,sum(t > 40 & t <= 60)); % leak
gas(t > 60) = 120 + 5*randn(1,sum(t > 60)); % emergency

% ---- IMU Acceleration Magnitude ----
acc_mag = 1 + 0.05*randn(1,N);           % normal motion
acc_mag(t == 70) = 4.5;                  % fall impact spike

% ---- IMU Gyro Magnitude ----
gyro_mag = 20 + 2*randn(1,N);
gyro_mag(t == 70) = 120;                 % rotation during fall

% ---- Temperature (°C) ----
temp = 28 + 0.5*randn(1,N);
temp(t > 55) = temp(t > 55) + 3;         % temp rise near fire

% ---- Humidity (%) ----
humidity = 60 + 2*randn(1,N);
humidity(t > 55) = humidity(t > 55) - 5; % humidity drop near heat

%% ==============================
%  FIGURE SETUP
% ===============================

figure('Color','w','Position',[100 100 1200 700]); %[output:810aa653]

subplot(3,2,1); hGas = plot(t(1),gas(1),'LineWidth',2); %[output:810aa653]
title('Gas Concentration (ppm)'); %[output:810aa653]
ylabel('ppm'); grid on; xlim([0 T]); ylim([0 150]); %[output:810aa653]

subplot(3,2,2); hAcc = plot(t(1),acc_mag(1),'LineWidth',2); %[output:810aa653]
title('Acceleration Magnitude'); %[output:810aa653]
ylabel('|a| (g)'); grid on; xlim([0 T]); ylim([0 6]); %[output:810aa653]

subplot(3,2,3); hGyro = plot(t(1),gyro_mag(1),'LineWidth',2); %[output:810aa653]
title('Gyroscope Magnitude'); %[output:810aa653]
ylabel('|ω| (deg/s)'); grid on; xlim([0 T]); ylim([0 150]); %[output:810aa653]

subplot(3,2,4); hTemp = plot(t(1),temp(1),'LineWidth',2); %[output:810aa653]
title('Temperature'); %[output:810aa653]
ylabel('°C'); grid on; xlim([0 T]); ylim([20 40]); %[output:810aa653]

subplot(3,2,5); hHum = plot(t(1),humidity(1),'LineWidth',2); %[output:810aa653]
title('Humidity'); %[output:810aa653]
ylabel('%'); grid on; xlim([0 T]); ylim([40 80]); %[output:810aa653]

sgtitle('Module 1: Sensor Layer Simulation (ESP Inputs)','FontSize',14,'FontWeight','bold'); %[output:810aa653]

%% ==============================
%  ANIMATION LOOP
% ===============================

for k = 2:N %[output:group:884de21f]
    set(hGas,  'XData',t(1:k),'YData',gas(1:k)); %[output:810aa653]
    set(hAcc,  'XData',t(1:k),'YData',acc_mag(1:k));
    set(hGyro, 'XData',t(1:k),'YData',gyro_mag(1:k));
    set(hTemp, 'XData',t(1:k),'YData',temp(1:k));
    set(hHum,  'XData',t(1:k),'YData',humidity(1:k));

    drawnow;
    pause(0.05);  % controls animation speed
end %[output:group:884de21f]


